const e = $input.first().json;
const remitente = (e.from && (e.from.text || e.from.value?.[0]?.address)) || '';
const asunto = e.subject || '';
const cuerpo = (e.text || e.snippet || '').substring(0, 1500);

const now = new Date();
const propuesta = new Date(now);
propuesta.setDate(propuesta.getDate() + 1);
while (propuesta.getDay() === 0 || propuesta.getDay() === 6) propuesta.setDate(propuesta.getDate() + 1);
propuesta.setHours(10, 0, 0, 0);
const propuesta_fin = new Date(propuesta.getTime() + 30 * 60000);

const system_prompt = `Eres el asistente ejecutivo con IA de A2K Digital Studio. Clasificas correos entrantes y redactas la respuesta.

Correo recibido:
- de: ${remitente}
- asunto: ${asunto}
- cuerpo: ${cuerpo}

Reglas de clasificacion:
- REUNION: pide agendar una llamada, reunion o cita.
- URGENTE: cliente con un problema o solicitud que necesita atencion humana pronto, pero no pide reunion.
- OTRO: boletin, spam, notificacion automatica, o correo sin accion clara.

Responde UNICAMENTE con un JSON valido, sin texto extra:
- "categoria": "REUNION" o "URGENTE" o "OTRO"
- "resumen": resumen de 1 frase para el ejecutivo
- "asunto_respuesta": asunto corto para la respuesta (agregar "Re: " si aplica)
- "respuesta_sugerida": cuerpo de la respuesta en espanol, profesional y calido, maximo 4 frases. Si es REUNION, confirma el horario propuesto: ${propuesta.toLocaleString('es-VE')}.`;

return [{ json: { ...e, remitente, system_prompt, propuesta_inicio: propuesta.toISOString(), propuesta_fin: propuesta_fin.toISOString() } }];

const original = $('Armar Prompt de Triage').first().json;
const resp = $input.first().json;
const textoBruto = resp.message.content;
const limpio = textoBruto.trim().replace(/^```json\s*/i, '').replace(/```\s*$/, '');
const contenido = JSON.parse(limpio);
return [{ json: { ...contenido, messageId: original.id, remitente: original.remitente, propuesta_inicio: original.propuesta_inicio, propuesta_fin: original.propuesta_fin } }];
